_etsy_font_cache = {}

def get_ui_font(size: int, serif: bool = False):
    key = (size, serif)
    if key in _etsy_font_cache:
        return _etsy_font_cache[key]
    candidates = [
        "DejaVuSerif.ttf" if serif else "DejaVuSans.ttf",
        "DejaVuSans.ttf",
        "Arial.ttf",
    ]
    for name in candidates:
        try:
            _etsy_font_cache[key] = ImageFont.truetype(name, size)
            return _etsy_font_cache[key]
        except Exception:
            pass
    _etsy_font_cache[key] = ImageFont.load_default()
    return _etsy_font_cache[key]


def _flatten_on_bg(img: Image.Image, bg_rgb=(248, 248, 246)) -> Image.Image:
    base = Image.new("RGBA", img.size, (*bg_rgb, 255))
    base.paste(img, (0, 0), img)
    return base


def make_simple_ruler(height_px: int, width_px: int = 84, cm_count: int = 6) -> Image.Image:
    ruler = Image.new("RGBA", (width_px, height_px), (229, 205, 181, 245))
    d = ImageDraw.Draw(ruler)
    d.rectangle((0, 0, width_px - 1, height_px - 1), outline=(177, 146, 119, 255), width=2)

    tick_color = (110, 86, 66, 255)
    label_font = get_ui_font(max(16, int(width_px * 0.22)), serif=False)
    px_per_cm = height_px / max(1, cm_count)

    for cm in range(cm_count + 1):
        y = int(round(cm * px_per_cm))
        y = min(height_px - 1, y)
        d.line((0, y, width_px - 8, y), fill=tick_color, width=2)
        if cm < cm_count:
            label = str(cm)
            bbox = d.textbbox((0, 0), label, font=label_font)
            text_w = bbox[2] - bbox[0]
            text_h = bbox[3] - bbox[1]
            d.text((width_px - text_w - 12, y + 4 - bbox[1]), label, font=label_font, fill=tick_color)
        if cm == cm_count:
            label = str(cm)
            bbox = d.textbbox((0, 0), label, font=label_font)
            text_w = bbox[2] - bbox[0]
            text_h = bbox[3] - bbox[1]
            d.text((width_px - text_w - 12, y - text_h - 4 - bbox[1]), label, font=label_font, fill=tick_color)
        if cm == cm_count:
            continue
        # 10 mm divisions per centimeter
        for mm in range(1, 10):
            yy = int(round(y + mm * (px_per_cm / 10.0)))
            if yy >= height_px:
                break
            if mm == 5:
                x2 = int(width_px * 0.65)
                w = 2
            else:
                x2 = int(width_px * 0.45)
                w = 1
            d.line((0, yy, x2, yy), fill=tick_color, width=w)
    return ruler



