_EMBEDDED_WATERMARKS = {}


def load_embedded_watermark(b64_string: str) -> Image.Image:
    cached = _EMBEDDED_WATERMARKS.get(b64_string)
    if cached is None:
        cached = Image.open(io.BytesIO(base64.b64decode(b64_string))).convert("RGBA")
        _EMBEDDED_WATERMARKS[b64_string] = cached
    return cached.copy()


def apply_full_canvas_overlay(base_img: Image.Image, overlay_img: Image.Image) -> Image.Image:
    base = base_img.convert("RGBA").copy()
    overlay = overlay_img.convert("RGBA")
    if overlay.size != base.size:
        overlay = overlay.resize(base.size, Image.Resampling.LANCZOS)
    base.alpha_composite(overlay)
    return base


def build_4000_repeat_from_tile(tile_img: Image.Image, tile_target_px: int = 2000) -> Image.Image:
    tile = tile_img.convert("RGBA")
    if tile.size != (tile_target_px, tile_target_px):
        tile = resize_alpha_safe(tile, (tile_target_px, tile_target_px), Image.Resampling.LANCZOS)
    repeated = Image.new("RGBA", (tile_target_px * 2, tile_target_px * 2), (0, 0, 0, 0))
    for i in range(2):
        for j in range(2):
            repeated.paste(tile, (i * tile_target_px, j * tile_target_px), tile)
    return repeated


def make_repeat_preview_with_handle(tile_img: Image.Image) -> Image.Image:
    repeated = build_4000_repeat_from_tile(tile_img)
    handle_overlay = load_embedded_watermark(SMALL_HANDLE_WATERMARK_B64)
    return apply_full_canvas_overlay(repeated, handle_overlay)


def make_etsy_main_image(tile_img: Image.Image, background_rgb=(250, 250, 248)) -> Image.Image:
    base = _flatten_on_bg(tile_img.convert("RGBA"), background_rgb)
    center_overlay = load_embedded_watermark(CENTER_LOGO_WATERMARK_B64)
    return apply_full_canvas_overlay(base, center_overlay)


def make_etsy_measurement_preview(tile_img: Image.Image, tile_px: int = None, dpi: int = 300, handle: str = DEFAULT_HANDLE_TEXT) -> Image.Image:
    """Create an Etsy size reference image with a 2 x 2 cm grid.
    No ruler is added; the larger headline and grid note explain the scale.
    """
    if tile_px is None:
        tile_px = int(tile_img.width)
    page_w = page_h = 2000
    bg = (243, 243, 241)
    page = Image.new("RGBA", (page_w, page_h), (*bg, 255))
    d = ImageDraw.Draw(page)

    title_font = get_ui_font(54, serif=True)
    subtitle_font = get_ui_font(46, serif=True)
    info_font = get_ui_font(34, serif=False)
    info_font_small = get_ui_font(32, serif=False)
    footer_font = get_ui_font(42, serif=False)

    cm = tile_px / dpi * 2.54
    inch = cm / 2.54
    grid_cm = 2.0
    grid_in = grid_cm / 2.54

    title_1 = "TILE SIZE PREVIEW"
    title_2 = f"JPEG & TIFF · {tile_px} × {tile_px} px · {dpi} DPI"
    info_line_1 = f"Tile size: approx. {cm:.1f} × {cm:.1f} cm / {inch:.1f} × {inch:.1f} in"
    info_line_2 = f"Each grid square: approx. {grid_cm:.0f} × {grid_cm:.0f} cm / {grid_in:.1f} × {grid_in:.1f} in"

    for text_line, y, font in [
        (title_1, 72, title_font),
        (title_2, 146, subtitle_font),
        (info_line_1, 224, info_font),
        (info_line_2, 274, info_font_small),
    ]:
        bbox = d.textbbox((0, 0), text_line, font=font)
        tw = bbox[2] - bbox[0]
        d.text(((page_w - tw) / 2, y - bbox[1]), text_line, font=font, fill=(54, 50, 48, 255))

    preview_size = 1380
    x0 = (page_w - preview_size) // 2
    y0 = 350
    x1 = x0 + preview_size
    y1 = y0 + preview_size

    flattened = _flatten_on_bg(tile_img.convert("RGBA"), (250, 250, 248))
    preview = flattened.resize((preview_size, preview_size), Image.Resampling.LANCZOS)
    page.paste(preview, (x0, y0))

    px_per_cm = preview_size / max(cm, 1e-6)
    grid_step = px_per_cm * grid_cm
    grid_color = (145, 145, 145, 115)
    bold_grid_color = (115, 115, 115, 150)
    n_steps = int(math.ceil(preview_size / max(grid_step, 1)))
    for i in range(n_steps + 1):
        pos = int(round(i * grid_step))
        xx = x0 + pos
        yy = y0 + pos
        if x0 <= xx <= x1:
            d.line((xx, y0, xx, y1), fill=bold_grid_color if i % 2 == 0 else grid_color, width=1)
        if y0 <= yy <= y1:
            d.line((x0, yy, x1, yy), fill=bold_grid_color if i % 2 == 0 else grid_color, width=1)

    d.rectangle((x0, y0, x1, y1), outline=(202, 202, 198, 255), width=2)

    marker = 16
    mc = (151, 181, 138, 220)
    for (cx, cy, sx, sy) in [(x0, y0, 1, 1), (x1, y0, -1, 1), (x0, y1, 1, -1), (x1, y1, -1, -1)]:
        d.line((cx, cy, cx + sx * marker, cy), fill=mc, width=2)
        d.line((cx, cy, cx, cy + sy * marker), fill=mc, width=2)

    footer = handle.strip() or DEFAULT_HANDLE_TEXT
    bbox = d.textbbox((0, 0), footer, font=footer_font)
    tw = bbox[2] - bbox[0]
    d.text(((page_w - tw) / 2, 1852 - bbox[1]), footer, font=footer_font, fill=(128, 100, 92, 255))
    return page


def pil_image_to_jpeg_bytes(img: Image.Image, dpi: int = 300, quality: int = 95) -> bytes:
    buf = io.BytesIO()
    img.convert("RGB").save(buf, format="JPEG", quality=quality, subsampling=0, dpi=(dpi, dpi), icc_profile=SRGB_ICC_PROFILE)
    return buf.getvalue()


def pil_image_to_png_bytes(img: Image.Image, dpi: int = 300) -> bytes:
    buf = io.BytesIO()
    img.save(buf, format="PNG", dpi=(dpi, dpi), icc_profile=SRGB_ICC_PROFILE)
    return buf.getvalue()


