def open_uploaded_png(uploaded_file) -> Image.Image:
    img = Image.open(uploaded_file).convert("RGBA")
    img = normalize_to_srgb(img)
    return img


def recolor_line_art(motif: Image.Image, rgb) -> Image.Image:
    """Replaces the color of every visible pixel with a single flat color,
    keeping the original alpha (so anti-aliased line edges stay smooth).
    Fully transparent pixels are left completely untouched - only pixels
    that are actually visible in the PNG get recolored.
    Made for uniform-color line art - shaded/sketch-style artwork with
    varying tones would lose that variation, since this ignores the
    original RGB entirely and only keeps shape (alpha)."""
    rgba = np.array(motif.convert("RGBA"))
    visible = rgba[..., 3] > 0
    rgba[visible, 0] = rgb[0]
    rgba[visible, 1] = rgb[1]
    rgba[visible, 2] = rgb[2]
    return Image.fromarray(rgba, "RGBA")


def load_motifs_batch(files):
    motifs = []
    if not files:
        return motifs
    for f in files:
        img = open_uploaded_png(f)
        img = crop_to_content(img, padding=4)
        motifs.append(img)
    return motifs


def detect_sheet_parts(
    sheet: Image.Image,
    proximity_px: int = 18,
    min_visible_area: int = 80,
    padding: int = 8,
):
    """Detect separated artwork clusters in a transparent PNG sheet.

    `proximity_px` grows the visible mask before connected-component analysis.
    This lets nearby pieces such as an animal and its ball be recognised as one
    motif without changing the original pixels.
    """
    rgba = np.asarray(sheet.convert("RGBA"))
    alpha = rgba[:, :, 3]
    visible = alpha > 10
    if not visible.any():
        return []

    grouped_mask = visible
    if proximity_px > 0:
        grouped_mask = binary_dilation(visible, iterations=int(proximity_px))

    labels, count = ndi_label(grouped_mask)
    slices = find_objects(labels)
    parts = []
    for component_id, component_slice in enumerate(slices, start=1):
        if component_slice is None:
            continue
        ys, xs = component_slice
        # Use the original alpha inside the dilated component's bounds to filter noise.
        visible_area = int(visible[ys, xs].sum())
        if visible_area < int(min_visible_area):
            continue
        x0 = max(0, xs.start - padding)
        x1 = min(sheet.width, xs.stop + padding)
        y0 = max(0, ys.start - padding)
        y1 = min(sheet.height, ys.stop + padding)
        parts.append({
            "component_id": component_id,
            "bbox": (x0, y0, x1, y1),
            "visible_area": visible_area,
            "preview": crop_to_content(sheet.crop((x0, y0, x1, y1)), padding=4),
        })

    # Natural reading order gives stable numbering in the manual grouping UI.
    parts.sort(key=lambda part: (part["bbox"][1], part["bbox"][0]))
    return parts


def combine_sheet_groups(sheet: Image.Image, parts, group_ids, included):
    grouped = {}
    for part, group_id, use_part in zip(parts, group_ids, included):
        if not use_part:
            continue
        grouped.setdefault(int(group_id), []).append(part)

    motifs = []
    for group_id in sorted(grouped):
        group_parts = grouped[group_id]
        x0 = min(part["bbox"][0] for part in group_parts)
        y0 = min(part["bbox"][1] for part in group_parts)
        x1 = max(part["bbox"][2] for part in group_parts)
        y1 = max(part["bbox"][3] for part in group_parts)
        motif = crop_to_content(sheet.crop((x0, y0, x1, y1)), padding=4)
        motifs.append(motif)
    return motifs



def make_slot_isolated_preview(motif, final_rotation, flip, flip_after_rotation=False, size=(420, 300)):
    """UI-only preview of one slot. It never changes the exported pattern."""
    preview_w, preview_h = size
    preview_bg = Image.new("RGBA", size, (250, 250, 250, 255))
    transparent = Image.new("RGBA", size, (0, 0, 0, 0))
    slot = {
        "x": preview_w // 2,
        "y": preview_h // 2,
        "width": int(min(preview_w, preview_h) * 0.58),
        "rotation": final_rotation,
        "flip": flip,
        "flip_after_rotation": flip_after_rotation,
    }
    placed = place_motif_on_canvas(transparent, crop_to_content(motif), slot, max(size))
    preview_bg.alpha_composite(placed)
    return preview_bg


def make_slot_locator_preview(template, selected_slot_id, size=420):
    """UI-only map showing the selected slot position in the complete tile."""
    image = Image.new("RGBA", (size, size), (250, 250, 250, 255))
    draw = ImageDraw.Draw(image)
    all_slots = template["main"] + template["secondary"]
    scale = size / CANVAS_SIZE

    for slot in all_slots:
        x = int(slot["x"] * scale)
        y = int(slot["y"] * scale)
        selected = slot["id"] == selected_slot_id
        radius = 15 if selected else 7
        fill = (185, 78, 78, 230) if selected else (162, 181, 162, 180)
        draw.ellipse((x-radius, y-radius, x+radius, y+radius), fill=fill)
        if selected:
            draw.ellipse(
                (x-radius-4, y-radius-4, x+radius+4, y+radius+4),
                outline=(185, 78, 78, 255), width=3,
            )
            draw.text((x + 20, y - 10), f"Slot {slot['id']}", fill=(80, 45, 45, 255))

    draw.rectangle((1, 1, size-2, size-2), outline=(220, 217, 208, 255), width=2)
    return image


def make_motif_size_preview(motif: Image.Image, scale_percent: int = 100, preview_size: int = 280) -> Image.Image:
    """Create a sharp checkerboard preview without changing the source motif.

    The motif is first cropped to visible content, then scaled relative to a
    consistent preview box. This helper is used only for the UI; pattern export
    continues to use the original full-resolution PNG.
    """
    motif = crop_to_content(motif.convert("RGBA"), padding=4)
    motif = decontaminate_white_matte(motif)
    motif = bleed_rgb_into_transparency(motif)
    preview_size = max(120, int(preview_size))

    # Subtle checkerboard so transparency stays visible on every browser/theme.
    tile = max(10, preview_size // 14)
    background = Image.new("RGBA", (preview_size, preview_size), (255, 255, 255, 255))
    draw = ImageDraw.Draw(background)
    light = (248, 248, 248, 255)
    for y in range(0, preview_size, tile):
        for x in range(0, preview_size, tile):
            if ((x // tile) + (y // tile)) % 2:
                draw.rectangle((x, y, min(x + tile - 1, preview_size - 1), min(y + tile - 1, preview_size - 1)), fill=light)

    base_box = int(preview_size * 0.72)
    target_long_side = max(1, int(round(base_box * max(1, scale_percent) / 100.0)))
    ratio = min(target_long_side / max(1, motif.width), target_long_side / max(1, motif.height))
    new_size = (max(1, int(round(motif.width * ratio))), max(1, int(round(motif.height * ratio))))
    resized = motif.resize(new_size, Image.Resampling.LANCZOS)
    x = (preview_size - resized.width) // 2
    y = (preview_size - resized.height) // 2
    background.alpha_composite(resized, (x, y))
    return background


def motifs_to_zip(motifs, prefix="motif"):
    buffer = io.BytesIO()
    with zipfile.ZipFile(buffer, "w", compression=zipfile.ZIP_DEFLATED) as archive:
        for index, motif in enumerate(motifs, start=1):
            png = io.BytesIO()
            motif.save(png, format="PNG", optimize=True, icc_profile=SRGB_ICC_PROFILE)
            archive.writestr(f"{prefix}_{index:02d}.png", png.getvalue())
    buffer.seek(0)
    return buffer.getvalue()


def motif_upload_widget(title: str, key_prefix: str):
    st.markdown(f"**{title}**")

    recolor_on = st.checkbox(
        "Recolor line art",
        value=False,
        key=f"{key_prefix}_recolor_on",
        help="Replaces all visible line color with one flat color you pick below. "
             "Best for solid-color line art on a transparent background.",
    )
    recolor_rgb = None
    if recolor_on:
        if f"{key_prefix}_recolor_hex" not in st.session_state:
            st.session_state[f"{key_prefix}_recolor_hex"] = "#3A3A3A"
        picked_hex = _bg_color_picker(
            default=st.session_state[f"{key_prefix}_recolor_hex"],
            key=f"{key_prefix}_recolor_picker",
        )
        if picked_hex:
            st.session_state[f"{key_prefix}_recolor_hex"] = picked_hex
        hex_clean = st.session_state[f"{key_prefix}_recolor_hex"].strip().lstrip("#")
        try:
            recolor_rgb = tuple(int(hex_clean[i:i+2], 16) for i in (0, 2, 4))
        except Exception:
            recolor_rgb = (58, 58, 58)

    def maybe_recolor(img):
        return recolor_line_art(img, recolor_rgb) if recolor_on and recolor_rgb else img

    mode = st.radio(
        "How should this upload be interpreted?",
        options=["Separate PNG files", "One complete motif", "Motif sheet — auto split"],
        horizontal=True,
        key=f"{key_prefix}_mode",
    )

    if mode == "Separate PNG files":
        files = st.file_uploader(
            "Upload one PNG per motif",
            type=["png"],
            accept_multiple_files=True,
            key=f"{key_prefix}_separate_files",
        )
        return [maybe_recolor(m) for m in load_motifs_batch(files)]

    uploaded = st.file_uploader(
        "Upload one transparent PNG",
        type=["png"],
        accept_multiple_files=False,
        key=f"{key_prefix}_single_file",
    )
    if not uploaded:
        return []

    sheet = open_uploaded_png(uploaded)
    sheet = maybe_recolor(sheet)
    if mode == "One complete motif":
        motif = crop_to_content(sheet, padding=4)
        st.image(make_motif_size_preview(motif, 100), caption="Complete PNG kept as one motif", width=240)
        return [motif]

    settings_col, preview_col = st.columns([1, 2])
    with settings_col:
        proximity = st.slider(
            "Group nearby parts",
            min_value=0,
            max_value=80,
            value=18,
            step=2,
            key=f"{key_prefix}_proximity",
            help="Increase when parts belonging to one motif are close but disconnected. Reduce when neighbouring motifs merge.",
        )
        min_area = st.slider(
            "Ignore tiny pieces smaller than",
            min_value=10,
            max_value=2000,
            value=80,
            step=10,
            key=f"{key_prefix}_min_area",
            help="Removes isolated specks while preserving small intentional details.",
        )

    parts = detect_sheet_parts(sheet, proximity_px=proximity, min_visible_area=min_area)
    with preview_col:
        st.image(sheet, caption="Uploaded motif sheet", use_container_width=True, output_format="PNG")

    if not parts:
        st.warning("No visible motifs were detected. Check that the PNG has transparency, or lower the minimum-area setting.")
        return []

    st.success(f"{len(parts)} artwork cluster(s) detected.")
    st.caption(
        "Each cluster starts as its own motif. To combine disconnected pieces, give them the same Group number. "
        "Untick Include to remove an unwanted speck or element."
    )

    group_ids = []
    included = []
    cols = st.columns(min(4, len(parts)))
    for index, part in enumerate(parts):
        with cols[index % len(cols)]:
            st.image(part["preview"], caption=f"Detected part {index + 1}", width=190, output_format="PNG")
            use_part = st.checkbox("Include", value=True, key=f"{key_prefix}_include_{index}")
            group_id = st.number_input(
                "Group",
                min_value=1,
                max_value=max(1, len(parts)),
                value=index + 1,
                step=1,
                key=f"{key_prefix}_group_{index}",
            )
            included.append(use_part)
            group_ids.append(group_id)

    motifs = combine_sheet_groups(sheet, parts, group_ids, included)
    if motifs:
        st.markdown("**Final motifs after grouping**")
        final_cols = st.columns(min(4, len(motifs)))
        for index, motif in enumerate(motifs):
            with final_cols[index % len(final_cols)]:
                st.image(
                    make_motif_size_preview(motif, 100),
                    caption=f"Motif {index + 1}",
                    width=220,
                    output_format="PNG",
                )
        st.download_button(
            "Download separated motifs (.zip)",
            data=motifs_to_zip(motifs, prefix=key_prefix),
            file_name=f"{key_prefix}_separated_motifs.zip",
            mime="application/zip",
            key=f"{key_prefix}_download_zip",
        )
    return motifs



# ============================================================
# Mockup Studio - drops the finished pattern into a real product
# photo. Assets are plain PNG files sitting next to this script
# (flat, no subfolders) - upload them alongside pattern_tool.py.
# ============================================================
# ============================================================
# Text phrase slots - embedded handwriting font (Sweet Apricot,
# licensed by the user) so short phrases can be scattered among
# the motifs, matching styles like "Let's play" / "Be my friend".
# ============================================================
SWEET_APRICOT_FONT_B64 = ""

_font_cache = {}

def get_phrase_font(size: int):
    if size not in _font_cache:
        font_bytes = base64.b64decode(SWEET_APRICOT_FONT_B64)
        _font_cache[size] = ImageFont.truetype(io.BytesIO(font_bytes), size)
    return _font_cache[size]


def render_text_motif(text: str, font_size: int, rgb) -> Image.Image:
    """Renders a short phrase as a transparent-background motif image,
    the same way an uploaded illustration motif would look, so it can be
    placed/rotated/scattered exactly like the animal motifs."""
    font = get_phrase_font(font_size)
    dummy = Image.new("RGBA", (10, 10))
    d = ImageDraw.Draw(dummy)
    bbox = d.textbbox((0, 0), text, font=font)
    pad = int(font_size * 0.15)
    w = (bbox[2] - bbox[0]) + pad * 2
    h = (bbox[3] - bbox[1]) + pad * 2
    img = Image.new("RGBA", (w, h), (0, 0, 0, 0))
    d = ImageDraw.Draw(img)
    d.text((pad - bbox[0], pad - bbox[1]), text, font=font, fill=(*rgb, 255))
    return img


def scatter_text_phrases(canvas: Image.Image, phrases, font_size: int, rgb, canvas_size=CANVAS_SIZE, seed=0):
    """Scatters each phrase once onto empty (transparent) areas of the
    canvas, avoiding heavy overlap with existing motifs, with a small
    random rotation for a natural hand-placed feel."""
    import random
    rng = random.Random(seed)
    existing_alpha = np.array(canvas.split()[-1])
    result = canvas.copy()

    for phrase in phrases:
        phrase = phrase.strip()
        if not phrase:
            continue
        motif = render_text_motif(phrase, font_size, rgb)
        angle = rng.uniform(-8, 8)
        rotated = motif.rotate(angle, expand=True, resample=Image.Resampling.BICUBIC)
        rw, rh = rotated.size

        placed = False
        for _ in range(40):
            x = rng.randint(0, max(1, canvas_size - rw))
            y = rng.randint(0, max(1, canvas_size - rh))
            region = existing_alpha[y:y+rh, x:x+rw]
            if region.size == 0:
                continue
            occupied_frac = (region > 10).mean()
            if occupied_frac < 0.05:
                result.alpha_composite(rotated, (x, y))
                existing_alpha[y:y+rh, x:x+rw] = np.maximum(
                    region, np.array(rotated.split()[-1])
                )
                placed = True
                break
        if not placed:
            pass  # skip phrase if no free spot found after 40 tries
    return result


main_motifs = []
secondary_motifs = []

if n_sec > 0:
    st.markdown(
        f"This template has **{n_main} large main slots** and **{n_sec} small secondary slots**. "
        "Upload and prepare the two groups separately."
    )
    col_main, col_sec = st.columns(2)
    with col_main:
        main_motifs = motif_upload_widget(
            f"Main motifs (up to {n_main}, or 1 to repeat)",
            f"{selected}_main",
        )
    with col_sec:
        secondary_motifs = motif_upload_widget(
            f"Secondary motifs (up to {n_sec}, or 1 to repeat)",
            f"{selected}_secondary",
        )
    all_motifs = main_motifs + secondary_motifs
else:
    st.markdown(
        f"This template needs **{n_total} motif(s)**. You can upload separate motifs, keep an entire PNG together, "
        "or split a motif sheet and correct the grouping before creating the pattern."
    )
    main_motifs = motif_upload_widget("Motifs", f"{selected}_main")
    all_motifs = main_motifs

if all_motifs:
    st.success(f"{len(all_motifs)} motif(s) detected.")
    st.markdown("**Adjust motif sizes**")
    st.caption(
        "Compare the motifs side by side and adjust only when one looks visually larger or smaller. "
        "The same uploaded motif keeps this exact size everywhere it repeats in the template."
    )

    motif_scale_percent = {"main": {}, "secondary": {}}

    # Main motifs
    if main_motifs:
        main_cols = st.columns(min(4, max(1, len(main_motifs))))
        for i, motif in enumerate(main_motifs):
            key = f"motif_scale_{selected}_main_{i}"
            if key not in st.session_state:
                st.session_state[key] = 100
            with main_cols[i % len(main_cols)]:
                label = f"Motif {i+1}" if not n_sec else f"Main {i+1}"
                scale_value = st.slider(
                    f"{label} size",
                    min_value=70,
                    max_value=130,
                    value=int(st.session_state[key]),
                    step=1,
                    key=key,
                    format="%d%%",
                )
                motif_scale_percent["main"][i] = scale_value
                st.image(
                    make_motif_size_preview(motif, scale_value),
                    caption=label,
                    width=240,
                    output_format="PNG",
                )

    # Secondary motifs, when the selected template has a second size group
    if secondary_motifs:
        st.markdown("**Secondary motifs**")
        sec_cols = st.columns(min(4, max(1, len(secondary_motifs))))
        for i, motif in enumerate(secondary_motifs):
            key = f"motif_scale_{selected}_secondary_{i}"
            if key not in st.session_state:
                st.session_state[key] = 100
            with sec_cols[i % len(sec_cols)]:
                label = f"Secondary {i+1}"
                scale_value = st.slider(
                    f"{label} size",
                    min_value=70,
                    max_value=130,
                    value=int(st.session_state[key]),
                    step=1,
                    key=key,
                    format="%d%%",
                )
                motif_scale_percent["secondary"][i] = scale_value
                st.image(
                    make_motif_size_preview(motif, scale_value),
                    caption=label,
                    width=240,
                    output_format="PNG",
                )

    st.divider()
    st.subheader("3. Assignment & Preview")

    slot_list = template["main"] + template["secondary"]
    main_pool = main_motifs if main_motifs else all_motifs
    sec_pool = secondary_motifs if secondary_motifs else main_pool

    # ("main"/"secondary", index) per slot
    assignment = {}
    for i, slot in enumerate(template["main"]):
        default_idx = slot.get("motif_index", i) % len(main_pool)
        assignment[slot["id"]] = ("main", default_idx)
    for i, slot in enumerate(template["secondary"]):
        default_idx = slot.get("motif_index", i) % len(sec_pool)
        assignment[slot["id"]] = ("secondary", default_idx)

    def resolve_motif(assign_tuple):
        pool_name, idx = assign_tuple
        pool = main_pool if pool_name == "main" else sec_pool
        return pool[idx % len(pool)]

    left_col, right_col = st.columns([1, 1])

    # Per-slot controls: assignment, additional rotation, and mirror.
    # The template's calibrated rotation always remains the base rotation.
    slot_flips = {}
    slot_rotation_offsets = {}

    with left_col:
        st.markdown("**Adjust individual slots**")
        st.caption(
            "Each slot can use a different motif, receive an additional rotation, "
            "and be mirrored independently. Template rotations stay unchanged underneath."
        )

        if st.button("Reset all slot rotations", key=f"reset_slot_rotations_{selected}"):
            for reset_slot in slot_list:
                st.session_state[f"slot_rotation_v1_{selected}_{reset_slot['id']}"] = 0
        for slot in slot_list:
            is_secondary = slot in template["secondary"]
            pool = sec_pool if is_secondary else main_pool
            pool_name = "secondary" if is_secondary else "main"
            options = list(range(len(pool)))
            current_idx = assignment[slot["id"]][1]

            st.markdown(f"**Slot {slot['id']}**")
            assignment_col, rotation_col, flip_col = st.columns([2.2, 2.4, 1.8])
            with assignment_col:
                # Use a versioned key and initialise it from the template default.
                # Older Streamlit widget state must never force every slot back to
                # Main 1 after rotation controls are added or files are re-uploaded.
                assignment_key = f"assign_v5_{selected}_{len(main_pool)}_{len(sec_pool)}_{slot['id']}"
                if assignment_key not in st.session_state:
                    st.session_state[assignment_key] = min(current_idx, len(options) - 1)
                elif st.session_state[assignment_key] not in options:
                    st.session_state[assignment_key] = min(current_idx, len(options) - 1)

                chosen = st.selectbox(
                    "Motif",
                    options,
                    format_func=lambda x, pn=pool_name: f"{'Secondary' if pn=='secondary' else 'Main'} {x+1}",
                    key=assignment_key,
                )
            with rotation_col:
                rotation_key = f"slot_rotation_v1_{selected}_{slot['id']}"
                if rotation_key not in st.session_state:
                    st.session_state[rotation_key] = 0
                slot_rotation_offsets[slot["id"]] = st.slider(
                    "Additional rotation",
                    min_value=-180,
                    max_value=180,
                    step=1,
                    key=rotation_key,
                    format="%d°",
                )
            with flip_col:
                # Versioned key prevents an older saved checkbox value from
                # overriding the current template default (important for Snails S01).
                flip_key = f"slot_flip_v3_{selected}_{slot['id']}"
                if flip_key not in st.session_state:
                    st.session_state[flip_key] = bool(slot.get("flip", False))
                slot_flips[slot["id"]] = st.checkbox(
                    "↔ Mirror horizontally",
                    key=flip_key,
                )

            assignment[slot["id"]] = (pool_name, chosen)

            # Optional orientation aid. The slot can always be rotated separately,
            # even when several slots use the same uploaded motif. This preview is
            # UI-only and never appears in the exported PNG.
            with st.expander(f"Show Slot {slot['id']}", expanded=False):
                preview_motif = crop_to_content(resolve_motif(assignment[slot["id"]]))
                preview_scale = motif_scale_percent.get(pool_name, {}).get(chosen, 100) / 100.0
                if preview_scale != 1.0:
                    scaled_w = max(1, int(round(preview_motif.width * preview_scale)))
                    scaled_h = max(1, int(round(preview_motif.height * preview_scale)))
                    preview_motif = resize_alpha_safe(
                        preview_motif, (scaled_w, scaled_h), Image.Resampling.LANCZOS
                    )

                final_rotation = slot["rotation"] + slot_rotation_offsets[slot["id"]]
                isolated_col, locator_col = st.columns(2)
                with isolated_col:
                    st.caption(
                        f"Assigned motif: {'Secondary' if pool_name == 'secondary' else 'Main'} {chosen + 1} · "
                        f"template {slot['rotation']}° + correction "
                        f"{slot_rotation_offsets[slot['id']]}° = {final_rotation}°"
                    )
                    st.image(
                        make_slot_isolated_preview(
                            preview_motif,
                            final_rotation,
                            slot_flips[slot["id"]],
                            slot.get("flip_after_rotation", False),
                        ),
                        use_container_width=True,
                        output_format="PNG",
                    )
                with locator_col:
                    st.caption("Position in the full pattern tile")
                    st.image(
                        make_slot_locator_preview(template, slot["id"]),
                        use_container_width=True,
                        output_format="PNG",
                    )

    canvas = Image.new("RGBA", (canvas_size, canvas_size), (0, 0, 0, 0))
    for slot in slot_list:
        slot_rotation = slot_rotation_offsets.get(slot["id"], 0)
        scaled_slot = {
            "x": int(slot["x"] * scale_factor),
            "y": int(slot["y"] * scale_factor),
            "width": int(slot["width"] * scale_factor),
            "rotation": slot["rotation"] + slot_rotation,
            "flip": slot_flips.get(slot["id"], slot.get("flip", False)),
            "flip_after_rotation": slot.get("flip_after_rotation", False),
        }
        pool_name, motif_idx = assignment[slot["id"]]
        motif = crop_to_content(resolve_motif(assignment[slot["id"]]))
        motif = decontaminate_white_matte(motif)
        motif = bleed_rgb_into_transparency(motif)

        # Apply the user's visual-size correction to every repetition of this motif.
        # Template-defined size groups (main/secondary) remain intact; this is only
        # a small per-upload correction for motifs that look optically larger/smaller.
        motif_scale = motif_scale_percent.get(pool_name, {}).get(motif_idx, 100) / 100.0
        scaled_slot["width"] = max(1, int(round(scaled_slot["width"] * motif_scale)))

        canvas = place_motif_on_canvas(canvas, motif, scaled_slot, canvas_size)

    with right_col:
        st.markdown("**Preview**")

        with st.expander("✏️ Add text phrases", expanded=False):
            st.caption("Place short handwritten-style phrases with their own position and rotation, just like a motif slot.")

            if "text_phrases_list" not in st.session_state:
                st.session_state.text_phrases_list = []

            if st.button("+ Add a phrase", key="add_phrase_btn"):
                st.session_state.text_phrases_list.append({
                    "text": "", "x": canvas_size // 2, "y": canvas_size // 2,
                    "rotation": 0, "size": 80,
                })

            if "text_phrase_color" not in st.session_state:
                st.session_state.text_phrase_color = "#5A4A3A"
            text_color_hex = _bg_color_picker(
                default=st.session_state.text_phrase_color, key="text_phrase_color_picker"
            )
            if text_color_hex:
                st.session_state.text_phrase_color = text_color_hex
            hex_clean = st.session_state.text_phrase_color.strip().lstrip("#")
            try:
                text_rgb = tuple(int(hex_clean[i:i+2], 16) for i in (0, 2, 4))
            except Exception:
                text_rgb = (90, 74, 58)

            remove_idx = None
            for i, entry in enumerate(st.session_state.text_phrases_list):
                st.markdown(f"**Phrase {i+1}**")
                entry["text"] = st.text_input("Text", value=entry["text"], key=f"phrase_text_{i}")
                col_x, col_y = st.columns(2)
                with col_x:
                    entry["x"] = st.slider("X position", 0, canvas_size, entry["x"], key=f"phrase_x_{i}")
                with col_y:
                    entry["y"] = st.slider("Y position", 0, canvas_size, entry["y"], key=f"phrase_y_{i}")
                entry["rotation"] = st.slider("Rotation", -180, 180, entry["rotation"], key=f"phrase_rot_{i}")
                entry["size"] = st.slider("Text size", 30, 200, entry["size"], key=f"phrase_size_{i}")
                if st.button("Remove this phrase", key=f"phrase_remove_{i}"):
                    remove_idx = i
            if remove_idx is not None:
                st.session_state.text_phrases_list.pop(remove_idx)
                st.rerun()

            for entry in st.session_state.text_phrases_list:
                if not entry["text"].strip():
                    continue
                motif = render_text_motif(entry["text"], entry["size"], text_rgb)
                rotated = motif.rotate(entry["rotation"], expand=True, resample=Image.Resampling.BICUBIC)
                rw, rh = rotated.size
                paste_x = entry["x"] - rw // 2
                paste_y = entry["y"] - rh // 2
                canvas.alpha_composite(rotated, (paste_x, paste_y))
                # Wrap around the seamless tile edges, same as motifs do
                offsets = []
                if paste_x < 0: offsets.append((canvas_size, 0))
                if paste_x + rw > canvas_size: offsets.append((-canvas_size, 0))
                if paste_y < 0: offsets.append((0, canvas_size))
                if paste_y + rh > canvas_size: offsets.append((0, -canvas_size))
                if paste_x < 0 and paste_y < 0: offsets.append((canvas_size, canvas_size))
                if paste_x + rw > canvas_size and paste_y < 0: offsets.append((-canvas_size, canvas_size))
                if paste_x < 0 and paste_y + rh > canvas_size: offsets.append((canvas_size, -canvas_size))
                if paste_x + rw > canvas_size and paste_y + rh > canvas_size: offsets.append((-canvas_size, -canvas_size))
                for dx, dy in offsets:
                    canvas.alpha_composite(rotated, (paste_x + dx, paste_y + dy))

        line_color_on = st.checkbox(
            "Change line color", value=False, key="line_color_on",
            help="Replaces every visible pixel in the finished pattern with one flat color. "
                 "Best for solid-color line art - shaded or multi-color motifs will flatten into a silhouette.",
        )
        if line_color_on:
            if "line_color_value" not in st.session_state:
                st.session_state.line_color_value = "#3A3A3A"
            picked_line_hex = _bg_color_picker(
                default=st.session_state.line_color_value, key="line_color_picker_widget"
            )
            if picked_line_hex:
                st.session_state.line_color_value = picked_line_hex
            try:
                line_hex_clean = st.session_state.line_color_value.strip().lstrip("#")
                if len(line_hex_clean) != 6:
                    raise ValueError
                line_rgb = tuple(int(line_hex_clean[i:i+2], 16) for i in (0, 2, 4))
                canvas = recolor_line_art(canvas, line_rgb)
            except Exception:
                st.warning("Enter a valid hex code, e.g. #3A3A3A — keeping original colors for now.")

        bg_mode = st.radio(
            "Background", ["Transparent", "Color"], horizontal=True, key="bg_mode_radio"
        )
        if bg_mode == "Color":
            if "bg_color_value" not in st.session_state:
                st.session_state.bg_color_value = "#D8C4B6"

            picked_hex = _bg_color_picker(
                default=st.session_state.bg_color_value, key="bg_color_picker_widget"
            )
            if picked_hex:
                st.session_state.bg_color_value = picked_hex

            bg_hex = st.session_state.bg_color_value
            try:
                bg_hex_clean = bg_hex.strip().lstrip("#")
                if len(bg_hex_clean) != 6:
                    raise ValueError
                bg_rgb = tuple(int(bg_hex_clean[i:i+2], 16) for i in (0, 2, 4))
            except Exception:
                st.warning("Enter a valid hex code, e.g. #F5F5F5 — using default gray for now.")
                bg_rgb = (245, 245, 245)
            export_canvas = Image.new("RGBA", canvas.size, (*bg_rgb, 255))
            export_canvas.paste(canvas, (0, 0), canvas)
        else:
            bg_rgb = (250, 250, 250)
            export_canvas = canvas

        preview_bg = Image.new("RGBA", canvas.size, (*bg_rgb, 255))
        preview_bg.paste(canvas, (0, 0), canvas)
        # Server-side sharp downscale for on-screen display — large enough to look genuinely sharp
        display_size = min(1600, preview_bg.width)
        display_preview = preview_bg.resize(
            (display_size, display_size), Image.Resampling.LANCZOS
        )
        st.image(display_preview, use_container_width=True, output_format="PNG")

        st.markdown("**Tile export**")
        file_slug = f"minimal_pattern_studio_{selected.lower().replace(' ', '_')}"

        if bg_mode == "Transparent":
            png_buf = io.BytesIO()
            export_canvas.save(png_buf, format="PNG", dpi=(DPI, DPI), icc_profile=SRGB_ICC_PROFILE)
            st.download_button(
                "📥 Download pattern tile as transparent PNG",
                data=png_buf.getvalue(),
                file_name=f"{file_slug}.png",
                mime="image/png",
                key=f"builder_tile_png_{selected}",
            )
        else:
            jpeg_buf = io.BytesIO()
            export_canvas.convert("RGB").save(
                jpeg_buf,
                format="JPEG",
                quality=100,
                subsampling=0,
                dpi=(DPI, DPI),
                icc_profile=SRGB_ICC_PROFILE,
            )
            st.download_button(
                "📥 Download pattern tile as JPEG",
                data=jpeg_buf.getvalue(),
                file_name=f"{file_slug}.jpg",
                mime="image/jpeg",
                key=f"builder_tile_jpeg_{selected}",
            )

            tiff_buf = io.BytesIO()
            export_canvas.save(
                tiff_buf,
                format="TIFF",
                compression="tiff_lzw",
                dpi=(DPI, DPI),
                icc_profile=SRGB_ICC_PROFILE,
            )
            st.download_button(
                "📥 Download pattern tile as TIFF",
                data=tiff_buf.getvalue(),
                file_name=f"{file_slug}.tiff",
                mime="image/tiff",
                key=f"builder_tile_tiff_{selected}",
            )

        render_listing_export_buttons(export_canvas, file_slug=file_slug, key_prefix=f"builder_{selected.lower().replace(' ', '_')}", dpi=DPI)
else:
    st.info("No motifs uploaded yet.")

st.divider()
st.subheader("3. Upload a finished design")
st.caption("Use this area when your seamless tile was created outside the template workflow and you only want the Etsy / listing outputs.")

finished_design = st.file_uploader(
    "Upload finished tile design",
    type=["png", "jpg", "jpeg", "tif", "tiff"],
    key="finished_design_upload",
)

if finished_design is not None:
    uploaded_tile = open_uploaded_png(finished_design)
    if uploaded_tile.width != uploaded_tile.height:
        st.warning("The uploaded design is not square. The listing exports work best with a square seamless tile.")

    preview_bg = _flatten_on_bg(uploaded_tile, (250, 250, 248))
    display_size = min(1600, preview_bg.width)
    display_preview = preview_bg.resize((display_size, display_size), Image.Resampling.LANCZOS)
    st.image(display_preview, use_container_width=True, output_format="PNG")

    upload_slug = Path(finished_design.name).stem.lower().replace(" ", "_")
    render_listing_export_buttons(uploaded_tile, file_slug=f"uploaded_design_{upload_slug}", key_prefix=f"upload_{upload_slug}", dpi=DPI)
else:
    st.info("Upload a finished design here anytime if you want the Etsy grid image, 4000px repeat preview, or watermark versions without using a template first.")
